1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	interface Item {
15	  type: string;
16	}
17	
18	interface Step {
19	  op: string;
20	  items?: Item[];
21	}
22	
23	interface Scenario {
24	  customer: { yearsWithMHPCO: number };
25	  steps: Step[];
26	}
27	
28	const BLOCK_SIZE = 3;
29	const BLOCK_PREMIUM = 60;
30	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
31	
32	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
33	const isNonComponent = (item: Item): boolean => !isComponent(item);
34	
35	const sumBase = (items: Item[]): number =>
36	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
37	
38	const priceAlikeComponents = (alike: Item[]): number =>
39	  alike.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBase(alike);
40	
41	const partitionByType = (items: Item[]): Item[][] => {
42	  const groups: Record<string, Item[]> = {};
43	  items.forEach((item) => (groups[item.type] ??= []).push(item));
44	  return Object.values(groups);
45	};
46	
47	const priceComponents = (components: Item[]): number =>
48	  partitionByType(components).reduce(
49	    (sum, group) => sum + priceAlikeComponents(group),
50	    0,
51	  );
52	
53	const sumBasePremiums = (items: Item[]): number =>
54	  sumBase(items.filter(isNonComponent)) +
55	  priceComponents(items.filter(isComponent));
56	
57	const applyFirstInsuranceSurcharge = (base: number): number =>
58	  Math.ceil((base * (PERCENT_BASE + FIRST_INSURANCE_PERCENT)) / PERCENT_BASE);
59	
60	const quotePremium = (items: Item[]): number =>
61	  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;
62	
63	const executeStep = (step: Step): { premium: number } => ({
64	  premium: quotePremium(step.items ?? []),
65	});
66	
67	export const runScenario = (input: unknown): { results: unknown[] } => {
68	  const scenario = input as Scenario;
69	  return { results: scenario.steps.map(executeStep) };
70	};
